const claimResult = (
  steps: Step[],
  step: ClaimStep,
  alreadyPaid: number,
): { payout: number; remainingCap: number } => {
  const insuredItems = insuredItemsForPolicy(steps, step.policy);
  const payout = Math.min(
    claimPayout(insuredItems, step.incident.damages),
    remainingCapFor(insuredItems, alreadyPaid),
  );
  return {
    payout,
    remainingCap: remainingCapFor(insuredItems, alreadyPaid + payout),
  };
};

export const runScenario = (scenario: Scenario): ScenarioResult => {
  const paidByPolicy: Record<number, number> = {};
  return {
    results: scenario.steps.map((step, index) => {
      if (step.op === "quote") {
        return {
          premium: quotePremium(scenario.customer, step.items, index > 0),
        };
      }
      const result = claimResult(
        scenario.steps,
        step,
        paidByPolicy[step.policy] ?? 0,
      );
      paidByPolicy[step.policy] = (paidByPolicy[step.policy] ?? 0) + result.payout;
      return result;
    }),
  };
};
